 {"id":"bd-jdg","title":"Implement structured tracing infrastructure (Cx::trace)","description":"## Purpose
Implement the structured tracing system that enables observability without stdout/stderr. All runtime events flow through `Cx::trace()` and are captured in a `TraceBuffer` for analysis, debugging, and replay.

## Design Principles (from AGENTS.md)

> Asupersync is a library/runtime. Core code should not write to stdout/stderr.
> Use structured tracing via `Cx::trace` (or equivalent) for observability.

## TraceEvent Enum

```rust
/// All observable events in the runtime
#[derive(Clone, Debug, PartialEq, Eq)]
pub enum TraceEvent {
    // === Time ===
    Tick {
        virtual_time: Time,
    },

    // === Task Lifecycle ===
    TaskSpawn {
        task_id: TaskId,
        region_id: RegionId,
        name: Option<String>,
        budget: Budget,
    },
    TaskPoll {
        task_id: TaskId,
        poll_count: u32,
    },
    TaskYield {
        task_id: TaskId,
        reason: YieldReason,
    },
    TaskCheckpoint {
        task_id: TaskId,
        cancel_observed: bool,
        mask_remaining: u32,
    },
    TaskComplete {
        task_id: TaskId,
        outcome_kind: OutcomeKind,  // Ok, Err, Cancelled, Panicked
        elapsed_virtual: Duration,
    },

    // === Region Lifecycle ===
    RegionOpen {
        region_id: RegionId,
        parent: Option<RegionId>,
        budget: Budget,
    },
    RegionCloseStart {
        region_id: RegionId,
    },
    RegionFinalizerRun {
        region_id: RegionId,
        finalizer_index: usize,
        is_async: bool,
    },
    RegionClose {
        region_id: RegionId,
        outcome_kind: OutcomeKind,
        children_count: usize,
        finalizers_run: usize,
    },

    // === Cancellation ===
    CancelRequest {
        target: CancelTarget,  // Region or Task
        reason: CancelReason,
        budget: Budget,
    },
    CancelPropagate {
        from: RegionId,
        to: RegionId,
    },
    CancelDrainStart {
        task_id: TaskId,
    },
    CancelDrainComplete {
        task_id: TaskId,
        checkpoints: u32,
    },

    // === Obligations ===
    ObligationReserve {
        obligation_id: ObligationId,
        kind: ObligationKind,
        holder: TaskId,
    },
    ObligationCommit {
        obligation_id: ObligationId,
    },
    ObligationAbort {
        obligation_id: ObligationId,
    },
    ObligationLeak {  // ERROR CASE
        obligation_id: ObligationId,
        holder: TaskId,
        region: RegionId,
    },

    // === Scheduler ===
    SchedulerPick {
        task_id: TaskId,
        lane: SchedulerLane,  // Cancel, Timed, Ready
        queue_depth: usize,
    },
    SchedulerWake {
        task_id: TaskId,
        reason: WakeReason,  // Timer, Channel, External
    },
    SchedulerStall {
        reason: StallReason,  // NoRunnableTasks, AllBlocked
    },

    // === Combinators ===
    RaceStart {
        participants: Vec<TaskId>,
    },
    RaceWinner {
        winner: TaskId,
        losers: Vec<TaskId>,
    },
    RaceLoserDrainStart {
        loser: TaskId,
    },
    RaceLoserDrainComplete {
        loser: TaskId,
    },

    // === User Events (for application tracing) ===
    User {
        name: String,
        data: TraceData,
    },
}

/// Serializable trace data for user events
#[derive(Clone, Debug, PartialEq, Eq)]
pub enum TraceData {
    None,
    Bool(bool),
    Int(i64),
    Uint(u64),
    String(String),
    List(Vec<TraceData>),
    Map(Vec<(String, TraceData)>),
}
```

## TraceBuffer

```rust
/// Ring buffer for trace events with configurable capacity
pub struct TraceBuffer {
    events: Vec<(Time, TraceEvent)>,
    capacity: usize,
    write_pos: usize,
    overflow_count: u64,
}

impl TraceBuffer {
    pub fn new(capacity: usize) -> Self;

    /// Record an event with timestamp
    pub fn push(&mut self, time: Time, event: TraceEvent);

    /// Get all events (in order)
    pub fn events(&self) -> impl Iterator<Item = &(Time, TraceEvent)>;

    /// Get events since a timestamp
    pub fn events_since(&self, since: Time) -> impl Iterator<Item = &(Time, TraceEvent)>;

    /// Get events matching a filter
    pub fn filter<F>(&self, f: F) -> Vec<&(Time, TraceEvent)>
    where
        F: Fn(&TraceEvent) -> bool;

    /// Clear all events
    pub fn clear(&mut self);

    /// Export for analysis (JSON-serializable)
    pub fn export(&self) -> TraceExport;

    /// Check if buffer has overflowed
    pub fn has_overflow(&self) -> bool;

    /// Get overflow count
    pub fn overflow_count(&self) -> u64;
}
```

## Trace Formatting (for debugging)

```rust
/// Format trace events for human-readable output
pub struct TraceFormatter {
    /// Include timestamps
    pub show_time: bool,
    /// Include task/region IDs
    pub show_ids: bool,
    /// Colorize output (for terminals)
    pub colorize: bool,
    /// Indent nested regions
    pub indent: bool,
}

impl TraceFormatter {
    /// Format a single event
    pub fn format_event(&self, time: Time, event: &TraceEvent) -> String;

    /// Format entire trace buffer
    pub fn format_buffer(&self, buffer: &TraceBuffer) -> String;

    /// Format as structured log (JSON lines)
    pub fn format_jsonl(&self, buffer: &TraceBuffer) -> String;
}

// Example output:
// [t0000] SPAWN task-1 in region-0 (budget: 1000 polls)
// [t0001] POLL task-1 (1/1000)
// [t0002] CHECKPOINT task-1 (cancel: false, mask: 0)
// [t0003] COMPLETE task-1 -> Ok (elapsed: 3 ticks)
```

## Cx::trace Integration

```rust
impl Cx for LabCx {
    fn trace(&self, event: TraceEvent) {
        self.runtime
            .borrow_mut()
            .trace_buffer
            .push(self.now(), event);
    }

    /// Convenience: trace user event with name
    fn trace_user(&self, name: &str, data: TraceData) {
        self.trace(TraceEvent::User {
            name: name.to_string(),
            data,
        });
    }
}
```

## Trace Analysis Helpers

```rust
impl TraceBuffer {
    /// Count events by type
    pub fn count_by_type(&self) -> HashMap<&'static str, usize>;

    /// Find task lifecycle (spawn to complete)
    pub fn task_lifecycle(&self, task_id: TaskId) -> Option<TaskLifecycle>;

    /// Find region lifecycle
    pub fn region_lifecycle(&self, region_id: RegionId) -> Option<RegionLifecycle>;

    /// Detect invariant violations in trace
    pub fn detect_violations(&self) -> Vec<TraceViolation>;

    /// Calculate statistics
    pub fn statistics(&self) -> TraceStatistics;
}

pub struct TraceStatistics {
    pub total_events: usize,
    pub tasks_spawned: usize,
    pub tasks_completed: usize,
    pub tasks_cancelled: usize,
    pub regions_opened: usize,
    pub regions_closed: usize,
    pub obligations_reserved: usize,
    pub obligations_committed: usize,
    pub obligations_aborted: usize,
    pub obligations_leaked: usize,  // Should be 0!
    pub max_concurrent_tasks: usize,
    pub max_region_depth: usize,
    pub total_polls: usize,
    pub total_checkpoints: usize,
}
```

## Testing Requirements

1. All runtime events emit correct trace events
2. TraceBuffer ring buffer works correctly (overflow, wrap-around)
3. Trace formatting is readable and parseable
4. TraceData serialization/deserialization works
5. Statistics calculations are accurate
6. Violation detection catches known issues
7. Export/import round-trips correctly

## Performance Considerations

- Trace events should be cheap to construct (no allocation on hot path)
- Use small enum variants where possible
- Ring buffer prevents unbounded memory growth
- Conditional tracing: `#[cfg(feature = "trace")]` for release builds

## Example Usage

```rust
async fn my_task(cx: &impl Cx) {
    // Automatic: TaskSpawn, TaskPoll events

    cx.trace_user("compute_start", TraceData::None);
    let result = compute_expensive();
    cx.trace_user("compute_end", TraceData::Int(result as i64));

    cx.checkpoint().await?;  // Automatic: TaskCheckpoint event

    // Automatic: TaskComplete event
}

// In test:
#[test]
fn test_my_task() {
    let mut runtime = LabRuntime::new(LabConfig::default());
    runtime.run(my_task);

    let stats = runtime.trace().statistics();
    assert_eq!(stats.obligations_leaked, 0);
    assert_eq!(stats.tasks_completed, 1);

    // Print trace for debugging
    println!("{}", TraceFormatter::default().format_buffer(runtime.trace()));
}
```

